module top_module(
  input [31:0] obf_in,
  input [4:0] shift_amount,
  input [1:0] shift_type,
  output reg [31:0] out
);always @(*) begin
  case (shift_type)
    2'b00: out = obf_in << shift_amount;
    2'b01: out = obf_in >> shift_amount;
    2'b10: out = $signed(obf_in) >>> shift_amount;
    default: out = obf_in;
  endcase
end

endmodule
